const publish = async (channelId, message) => {
  // 1) Append to durable log (async)
  const offset = await durableLog.append(channelId, message);
  // 2) Notify fan-out partition responsible for channelId
  const partition = partitionFor(channelId);
  await fanout.notify(partition, { channelId, offset });
};

// Fan-out service receives notification and pushes to gateways
fanout.on('notify', async ({ channelId, offset }) => {
  const msg = await durableLog.read(channelId, offset);
  const gateways = subscriptionDirectory.getGateways(channelId);
  gateways.forEach(gw => gw.push(msg));
});

